#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
    bool solve(vector<int>& nums, int target) {
        int left = 0;
        int right = nums.size() - 1;
        while(left <= right) {
            int mid = left + (right - left) / 2;
            if(nums[mid] == target) {
                return true;
            }
            if(nums[mid] < target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return false;
    }
};

int main() {
    int n;
    cin >> n;
    vector<int> v(n);
    for (auto &i:v) cin >> i;
    int target;
    cin >> target;
    Solution s;
    cout << s.solve(v, target) << endl;
    return 0;
}
